// Structured output schemas for document extraction
// These schemas constrain the AI response to guaranteed valid JSON
// Document-type-specific: each document type has its own extraction shape
//
// DESIGN: AI extracts pure financial facts. Clarification questions, gap
// detection, and user-facing text are generated by app code using the
// spec 13 decision trees. This keeps output tokens low (~350 vs ~1000)
// and makes questions deterministic and easy to iterate on.

// ═══ Shared types ═══

export interface ExtractedIncome {
  source: string
  amount: number
  period: 'monthly' | 'annual'
  confidence: number
  type: 'employment' | 'benefits' | 'rental' | 'self_employment' | 'pension_income' | 'maintenance' | 'other'
}

export interface DetectedPayment {
  payee: string
  amount: number
  frequency: 'monthly' | 'weekly' | 'quarterly' | 'annual' | 'one_off'
  confidence: number
  likely_category: 'mortgage' | 'rent' | 'insurance' | 'pension_contribution' | 'childcare' | 'loan_repayment' | 'child_maintenance' | 'utilities' | 'council_tax' | 'subscription' | 'unknown'
}

export interface SpendingCategory {
  category: string
  monthly_average: number
  transaction_count: number
}

// ═══ Bank statement extraction ═══

export interface BankStatementExtraction {
  document_type: 'bank_statement'
  provider: string
  account_number_last4: string | null
  account_type: 'current' | 'savings' | 'joint_current' | 'joint_savings' | 'unknown'
  is_joint: boolean
  joint_holder_name: string | null
  statement_period_start: string | null
  statement_period_end: string | null
  closing_balance: number | null
  income_deposits: ExtractedIncome[]
  regular_payments: DetectedPayment[]
  spending_categories: SpendingCategory[]
  notable_transactions: {
    description: string
    amount: number
    date: string | null
    reason_flagged: string
  }[]
}

export const BANK_STATEMENT_SCHEMA = {
  type: 'object' as const,
  additionalProperties: false as const,
  properties: {
    document_type: { type: 'string' as const, enum: ['bank_statement'] },
    provider: { type: 'string' as const },
    account_number_last4: { type: ['string', 'null'] as const },
    account_type: { type: 'string' as const, enum: ['current', 'savings', 'joint_current', 'joint_savings', 'unknown'] },
    is_joint: { type: 'boolean' as const },
    joint_holder_name: { type: ['string', 'null'] as const },
    statement_period_start: { type: ['string', 'null'] as const },
    statement_period_end: { type: ['string', 'null'] as const },
    closing_balance: { type: ['number', 'null'] as const },
    income_deposits: {
      type: 'array' as const,
      items: {
        type: 'object' as const,
        additionalProperties: false as const,
        properties: {
          source: { type: 'string' as const },
          amount: { type: 'number' as const },
          period: { type: 'string' as const, enum: ['monthly', 'annual'] },
          confidence: { type: 'number' as const },
          type: { type: 'string' as const, enum: ['employment', 'benefits', 'rental', 'self_employment', 'pension_income', 'maintenance', 'other'] },
        },
        required: ['source', 'amount', 'period', 'confidence', 'type'],
      },
    },
    regular_payments: {
      type: 'array' as const,
      items: {
        type: 'object' as const,
        additionalProperties: false as const,
        properties: {
          payee: { type: 'string' as const },
          amount: { type: 'number' as const },
          frequency: { type: 'string' as const, enum: ['monthly', 'weekly', 'quarterly', 'annual', 'one_off'] },
          confidence: { type: 'number' as const },
          likely_category: { type: 'string' as const, enum: ['mortgage', 'rent', 'insurance', 'pension_contribution', 'childcare', 'loan_repayment', 'child_maintenance', 'utilities', 'council_tax', 'subscription', 'unknown'] },
        },
        required: ['payee', 'amount', 'frequency', 'confidence', 'likely_category'],
      },
    },
    spending_categories: {
      type: 'array' as const,
      items: {
        type: 'object' as const,
  additionalProperties: false as const,
        properties: {
          category: { type: 'string' as const },
          monthly_average: { type: 'number' as const },
          transaction_count: { type: 'number' as const },
        },
        required: ['category', 'monthly_average', 'transaction_count'],
      },
    },
    notable_transactions: {
      type: 'array' as const,
      items: {
        type: 'object' as const,
  additionalProperties: false as const,
        properties: {
          description: { type: 'string' as const },
          amount: { type: 'number' as const },
          date: { type: ['string', 'null'] as const },
          reason_flagged: { type: 'string' as const },
        },
        required: ['description', 'amount', 'reason_flagged'],
      },
    },
  },
  required: ['document_type', 'provider', 'account_type', 'is_joint', 'income_deposits', 'regular_payments', 'spending_categories', 'notable_transactions'],
}

